        return left

    def _parse_unary(self) -> ASTNode:
        if self._is_op('-'):
            self._consume()
            operand = self._parse_unary()
            return ASTNode(type='unary', op='-', operand=operand)
        if self._is_op('+'):
            self._consume()
            return self._parse_unary()
        return self._parse_primary()

    def _parse_primary(self) -> ASTNode:
        token = self._current()
        if token is None:
            raise ValueError("Unexpected end of expression")

        if token[0] == 'num':
            self._consume()
            val = token[1]
            assert isinstance(val, float)
            return ASTNode(type='number', value=val)

        if token[0] == 'op' and token[1] == '(':
            self._consume()
            node = self._parse_additive()
            if not self._is_op(')'):
                raise ValueError("Unmatched opening parenthesis")
            self._consume()
            return node

        raise ValueError(f"Unexpected token: {token}")


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")
    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer.tokens)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == 'unary':
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val
        raise ValueError(f"Unknown unary operator: {node.op}")

