from __future__ import annotations
from dataclasses import dataclass
from typing import Optional, List, Tuple, Union


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional[ASTNode] = None
    right: Optional[ASTNode] = None
    operand: Optional[ASTNode] = None


class Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.tokens: List[Tuple[str, Union[str, float]]] = []
        self._tokenize()

    def _tokenize(self):
        while self.pos < len(self.expression):
            ch = self.expression[self.pos]
            if ch.isspace():
                self.pos += 1
            elif ch.isdigit() or ch == ".":
                self._read_number()
            elif ch in "+-*/()":
                self.tokens.append(("op", ch))
                self.pos += 1
            else:
                raise ValueError(f"Invalid token: {ch}")

    def _read_number(self):
        start = self.pos
        has_dot = False
        while self.pos < len(self.expression):
            ch = self.expression[self.pos]
            if ch.isdigit():
                self.pos += 1
            elif ch == "." and not has_dot:
                has_dot = True
                self.pos += 1
            else:
                break
        num_str = self.expression[start : self.pos]
        try:
            self.tokens.append(("num", float(num_str)))
        except ValueError:
            raise ValueError(f"Invalid number: {num_str}")


class Parser:
    def __init__(self, tokens: List[Tuple[str, Union[str, float]]]):
        self.tokens = tokens
        self.pos = 0

    def parse(self) -> ASTNode:
        if not self.tokens:
            raise ValueError("Empty expression")
        result = self._parse_additive()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected token: {self.tokens[self.pos]}")
        return result

    def _current(self) -> Optional[Tuple[str, Union[str, float]]]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def _consume(self) -> Tuple[str, Union[str, float]]:
        token = self._current()
        if token is None:
            raise ValueError("Unexpected end of expression")
        self.pos += 1
        return token

    def _is_op(self, ops: str) -> bool:
        token = self._current()
        if token is None:
            return False
        if token[0] != "op":
            return False
        val = token[1]
        return isinstance(val, str) and val in ops

    def _parse_additive(self) -> ASTNode:
        left = self._parse_multiplicative()
        while self._is_op("+-"):
            token = self._consume()
            op = token[1]
            assert isinstance(op, str)
            right = self._parse_multiplicative()
            left = ASTNode(type="binop", op=op, left=left, right=right)
        return left

    def _parse_multiplicative(self) -> ASTNode:
        left = self._parse_unary()
        while self._is_op("*/"):
            token = self._consume()
            op = token[1]
            assert isinstance(op, str)
            right = self._parse_unary()
            left = ASTNode(type="binop", op=op, left=left, right=right)
        return left

    def _parse_unary(self) -> ASTNode:
        if self._is_op("-"):
            self._consume()
            operand = self._parse_unary()
            return ASTNode(type="unary", op="-", operand=operand)
        if self._is_op("+"):
            self._consume()
            return self._parse_unary()
        return self._parse_primary()

    def _parse_primary(self) -> ASTNode:
        token = self._current()
        if token is None:
            raise ValueError("Unexpected end of expression")

        if token[0] == "num":
            self._consume()
            val = token[1]
            assert isinstance(val, float)
            return ASTNode(type="number", value=val)

        if token[0] == "op" and token[1] == "(":
            self._consume()
            node = self._parse_additive()
            if not self._is_op(")"):
                raise ValueError("Unmatched opening parenthesis")
            self._consume()
            return node

        raise ValueError(f"Unexpected token: {token}")


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")
    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer.tokens)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operator node missing operands")
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        if node.op == "-":
            return left_val - right_val
        if node.op == "*":
            return left_val * right_val
        if node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")


if __name__ == "__main__":
    tests = [
        "42",
        "-5",
        "3 + 4",
        "10 - 3 * 2",
        "(2 + 3) * 4",
        "-(3 + 2)",
        "10 / 2",
        "2 + 3 * 4 - 5 / 2",
        "((1 + 2) * (3 + 4))",
    ]

    for expr in tests:
        try:
            ast = parse(expr)
            result = evaluate(ast)
            print(f"{expr} = {result}")
        except Exception as e:
            print(f"{expr} -> Error: {e}")
